GUIDE_CSS = ':root{\n  --paper:#f7f1e6;--paper2:#fdfaf3;--ink:#211d18;--ink-soft:#5c544a;\n  --persimmon:#c8472f;--persimmon-dk:#9e3320;--celadon:#3f6b5c;--celadon-lt:#e4ede6;\n  --tiktok:#1f8f8a;--tiktok-dk:#136561;--tiktok-lt:#e0efed;--line:#e2d8c6;\n  --shadow:0 1px 2px rgba(33,29,24,.05),0 8px 24px -12px rgba(33,29,24,.18);\n  --shadow-lg:0 12px 40px -16px rgba(33,29,24,.35);\n  --serif:"Fraunces",Georgia,serif;--sans:"Hanken Grotesk",-apple-system,system-ui,sans-serif;\n  --safe-t:env(safe-area-inset-top,0px);--safe-b:env(safe-area-inset-bottom,0px);\n}\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}\nhtml{scroll-behavior:smooth;-webkit-text-size-adjust:100%}\nbody{font-family:var(--sans);color:var(--ink);line-height:1.55;background:var(--paper);\n  background-image:radial-gradient(circle at 12% 6%,rgba(200,71,47,.05),transparent 40%),\n    radial-gradient(circle at 88% 16%,rgba(31,143,138,.06),transparent 45%);\n  background-attachment:fixed;-webkit-font-smoothing:antialiased;overflow-x:hidden}\n.wrap{max-width:1180px;margin:0 auto;padding:0 16px}\n\n/* HEADER */\nheader.hero{padding:calc(28px + var(--safe-t)) 0 16px;text-align:center}\n.kicker{font-weight:600;letter-spacing:.3em;text-transform:uppercase;font-size:.66rem;color:var(--persimmon);margin-bottom:10px}\n.kicker::before,.kicker::after{content:"";display:inline-block;width:22px;height:1px;background:var(--persimmon);vertical-align:middle;margin:0 10px 4px}\nh1.title{font-family:var(--serif);font-weight:900;font-size:clamp(2.2rem,11vw,4.4rem);line-height:.95;letter-spacing:-.02em}\nh1.title em{font-style:italic;font-weight:500;color:var(--persimmon)}\n.subtitle{font-family:var(--serif);font-style:italic;font-size:clamp(.95rem,3.8vw,1.3rem);color:var(--ink-soft);margin-top:10px}\n.statline{margin-top:12px;font-size:.8rem;color:var(--ink-soft)}\n.statline b{color:var(--celadon);font-weight:700}.statline .ig{color:var(--persimmon)}.statline .tt{color:var(--tiktok)}\n\n/* INSTALL TIP */\n.tip{display:none;margin:14px 0 0;background:var(--paper2);border:1.5px solid var(--line);border-radius:14px;\n  padding:12px 14px;font-size:.82rem;color:var(--ink-soft);box-shadow:var(--shadow);position:relative;text-align:left;line-height:1.5}\n.tip b{color:var(--ink)}\n.tip .x{position:absolute;top:8px;right:10px;border:0;background:none;font-size:1.2rem;color:var(--ink-soft);cursor:pointer;line-height:1}\n\n/* CONTROLS */\n.controls{position:sticky;top:0;z-index:30;padding:10px 0 8px;margin-top:14px;\n  background:rgba(247,241,230,.94);backdrop-filter:blur(12px);-webkit-backdrop-filter:blur(12px);border-bottom:1px solid var(--line)}\n.controls .wrap{padding:0 16px}\n.searchbar{display:flex;align-items:center;gap:10px;background:var(--paper2);border:1.5px solid var(--line);\n  border-radius:999px;padding:12px 16px;box-shadow:var(--shadow)}\n.searchbar:focus-within{border-color:var(--persimmon);box-shadow:0 0 0 4px rgba(200,71,47,.1)}\n.searchbar svg{flex:none;color:var(--ink-soft)}\n.searchbar input{border:0;background:none;outline:none;font-family:var(--sans);font-size:1rem;width:100%;color:var(--ink);min-width:0}\n.searchbar input::placeholder{color:#a89c89}\n.clear-btn{border:0;background:none;cursor:pointer;color:var(--ink-soft);font-size:1.2rem;display:none;padding:0 2px}\n.segment{display:flex;border:1.5px solid var(--line);border-radius:999px;overflow:hidden;background:var(--paper2);box-shadow:var(--shadow);margin-top:9px}\n.segment button{flex:1;border:0;background:none;cursor:pointer;font-family:var(--sans);font-weight:700;font-size:.85rem;padding:11px 8px;color:var(--ink-soft);transition:all .15s}\n.segment button.active[data-plat="all"]{background:var(--ink);color:var(--paper2)}\n.segment button.active[data-plat="Instagram"]{background:var(--persimmon);color:#fff}\n.segment button.active[data-plat="TikTok"]{background:var(--tiktok);color:#fff}\n/* topic chips — horizontal swipe row on mobile */\n.chips{display:flex;gap:8px;margin-top:9px;overflow-x:auto;scroll-snap-type:x proximity;\n  -webkit-overflow-scrolling:touch;padding-bottom:2px;scrollbar-width:none}\n.chips::-webkit-scrollbar{display:none}\n.chip{flex:none;scroll-snap-align:start;font-family:var(--sans);font-size:.82rem;font-weight:600;cursor:pointer;\n  border:1.5px solid var(--line);background:var(--paper2);color:var(--ink-soft);padding:8px 14px;border-radius:999px;white-space:nowrap}\n.chip .n{opacity:.55;font-weight:500;margin-left:4px}\n.chip.active{background:var(--ink);border-color:var(--ink);color:var(--paper2)}\n.chip.active .n{opacity:.7}\n.resultline{font-size:.74rem;color:var(--ink-soft);margin-top:8px;letter-spacing:.02em}\n\n/* SECTIONS + CARDS */\n.section{padding:26px 0 4px;scroll-margin-top:170px}\n.section-head{display:flex;align-items:baseline;gap:12px;margin-bottom:16px;border-bottom:2px solid var(--ink);padding-bottom:8px}\n.section-head h2{font-family:var(--serif);font-weight:600;font-size:clamp(1.4rem,5.5vw,2rem);letter-spacing:-.01em}\n.section-head .cnt{font-weight:700;font-size:.78rem;color:var(--paper2);background:var(--persimmon);border-radius:999px;padding:3px 10px;align-self:center}\n.grid{display:grid;grid-template-columns:1fr;gap:14px}\n.card{background:var(--paper2);border:1px solid var(--line);border-radius:16px;display:flex;flex-direction:column;\n  box-shadow:var(--shadow);position:relative;overflow:hidden;\n  content-visibility:auto;contain-intrinsic-size:auto 320px}\n.card::before{content:"";position:absolute;left:0;top:0;bottom:0;width:4px;background:var(--persimmon);opacity:.85;z-index:1}\n.card.tt::before{background:var(--tiktok)}\n.cbody{padding:18px 18px 4px}\n.toprow{display:flex;justify-content:space-between;align-items:flex-start;gap:10px}\n.uploader{font-family:var(--serif);font-weight:600;font-size:1.08rem;line-height:1.2;word-break:break-word}\n.uploader .at{color:var(--persimmon);font-style:italic;font-weight:500}\n.card.tt .uploader .at{color:var(--tiktok-dk)}\n.topic-tag{flex:none;font-size:.62rem;font-weight:700;letter-spacing:.04em;text-transform:uppercase;color:var(--celadon);background:var(--celadon-lt);padding:3px 8px;border-radius:6px;white-space:nowrap}\n.platrow{display:flex;align-items:center;gap:8px;margin:8px 0 2px;flex-wrap:wrap}\n.plat{font-size:.62rem;font-weight:800;letter-spacing:.06em;text-transform:uppercase;padding:3px 9px;border-radius:999px}\n.plat.ig{color:#fff;background:var(--persimmon)}.plat.tt{color:#fff;background:var(--tiktok)}\n.metrics{display:flex;gap:10px;font-size:.74rem;color:var(--ink-soft);font-weight:600}\n.loc{display:flex;align-items:flex-start;gap:7px;margin:10px 0;font-size:.86rem;color:var(--persimmon-dk);font-weight:600;line-height:1.4;text-decoration:none}\n.card.tt .loc{color:var(--tiktok-dk)}\n.loc svg{flex:none;margin-top:2px}\n.loc span{border-bottom:1px dotted currentColor}\n.desc{font-size:.92rem;color:#34302a;line-height:1.55;margin-top:8px}\n.desc.clamp{display:-webkit-box;-webkit-line-clamp:4;-webkit-box-orient:vertical;overflow:hidden}\n.more{display:block;width:100%;text-align:left;background:none;border:0;color:var(--celadon);font-family:var(--sans);font-weight:700;font-size:.82rem;cursor:pointer;padding:10px 0 4px}\n.extra{display:none;margin-top:6px;border-top:1px dashed var(--line);padding-top:10px}\n.extra.open{display:block}\n.extra h4{font-size:.64rem;text-transform:uppercase;letter-spacing:.1em;color:var(--ink-soft);margin:0 0 5px}\n.extra .blk{font-size:.85rem;color:#4a443c;margin-bottom:12px;white-space:pre-wrap;line-height:1.5}\n.extra .orig{color:#6b6255}\n.tags{margin-top:8px;display:flex;flex-wrap:wrap;gap:6px}\n.tag{font-size:.72rem;color:var(--ink-soft);background:#efe7d6;border-radius:6px;padding:4px 9px;cursor:pointer;border:0;font-family:var(--sans)}\n.cardfoot{display:flex;gap:10px;align-items:stretch;padding:12px 18px calc(16px);margin-top:6px}\n.watch{flex:1;display:inline-flex;align-items:center;justify-content:center;gap:7px;font-weight:700;font-size:.92rem;\n  text-decoration:none;background:var(--ink);color:var(--paper2);padding:13px 14px;border-radius:11px;min-height:48px}\n.card.tt .watch{background:var(--tiktok-dk)}\n.card.ig .watch{background:var(--persimmon-dk)}\n.maplink{flex:none;display:inline-flex;align-items:center;gap:6px;font-weight:700;font-size:.88rem;text-decoration:none;\n  color:var(--celadon);border:1.5px solid var(--celadon);padding:0 16px;border-radius:11px;min-height:48px}\n.empty{text-align:center;padding:70px 16px;color:var(--ink-soft);font-family:var(--serif);font-style:italic;font-size:1.2rem;display:none}\nfooter{text-align:center;padding:40px 16px calc(40px + var(--safe-b));margin-top:24px;border-top:1px solid var(--line);color:var(--ink-soft);font-size:.78rem;line-height:1.7}\nfooter b{font-family:var(--serif);color:var(--ink)}\n.totop{position:fixed;right:16px;bottom:calc(16px + var(--safe-b));z-index:40;width:50px;height:50px;border-radius:50%;\n  background:var(--ink);color:var(--paper2);border:0;cursor:pointer;box-shadow:var(--shadow-lg);font-size:1.3rem;opacity:0;pointer-events:none;transition:opacity .25s,transform .2s}\n.totop.show{opacity:1;pointer-events:auto}\n.card[hidden],.section[hidden]{display:none!important}\n\n/* DESKTOP / TABLET */\n@media(min-width:680px){\n  .wrap{padding:0 22px}\n  header.hero{padding:56px 0 24px}\n  .controls{padding:14px 0 12px}\n  .controlrow{display:flex;gap:12px;align-items:center}\n  .searchbar{flex:1}\n  .segment{margin-top:0;flex:none}\n  .segment button{flex:none;padding:11px 18px}\n  .chips{flex-wrap:wrap;overflow:visible}\n  .grid{grid-template-columns:repeat(auto-fill,minmax(330px,1fr));gap:18px}\n}\n\n/* --- extra platforms (added by pipeline) --- */\n:root{--youtube:#cf2e2e;--facebook:#2f5fa8;--xcol:#1c1c1c;--reddit:#cf5a2e;}\n.card.yt::before{background:var(--youtube)}.plat.yt{color:#fff;background:var(--youtube)}.card.yt .watch{background:#9e1f1f}.card.yt .uploader .at{color:var(--youtube)}.card.yt .loc{color:#9e1f1f}\n.card.fb::before{background:var(--facebook)}.plat.fb{color:#fff;background:var(--facebook)}.card.fb .watch{background:#244c86}.card.fb .uploader .at{color:var(--facebook)}.card.fb .loc{color:#244c86}\n.card.xx::before{background:var(--xcol)}.plat.xx{color:#fff;background:var(--xcol)}.card.xx .watch{background:#000}.card.xx .uploader .at{color:var(--xcol)}\n.card.rd::before{background:var(--reddit)}.plat.rd{color:#fff;background:var(--reddit)}.card.rd .watch{background:#a8431f}.card.rd .uploader .at{color:var(--reddit)}\n.card.other::before{background:var(--celadon)}.plat.other{color:#fff;background:var(--celadon)}.card.other .watch{background:var(--celadon)}.card.other .uploader .at{color:var(--celadon)}\n.segment button.active[data-plat="YouTube"]{background:var(--youtube);color:#fff}\n.segment button.active[data-plat="Facebook"]{background:var(--facebook);color:#fff}\n.segment button.active[data-plat="X"]{background:var(--xcol);color:#fff}\n.segment button.active[data-plat="Reddit"]{background:var(--reddit);color:#fff}\n.segment button.active[data-plat="Other"]{background:var(--celadon);color:#fff}\n.badge-use{font-size:.7rem;font-weight:700;color:var(--celadon)}\n.badge-act{font-size:.6rem;font-weight:800;letter-spacing:.06em;text-transform:uppercase;color:var(--ink-soft);background:#efe7d6;border-radius:6px;padding:2px 7px}\n.lang-tag{font-size:.6rem;font-weight:700;letter-spacing:.05em;text-transform:uppercase;color:var(--ink-soft)}\n/* --- visited checklist --- */\n.card{position:relative}\n.vmark{display:inline-flex;align-items:center;gap:6px;font-size:.78rem;font-weight:700;color:var(--ink-soft);cursor:pointer;user-select:none;margin-left:auto}\n.vmark input{width:16px;height:16px;accent-color:var(--celadon);cursor:pointer;margin:0}\n.card.visited{opacity:.58}\n.card.visited::after{content:"\\2713 Visited";position:absolute;top:9px;right:9px;font-size:.58rem;font-weight:800;letter-spacing:.05em;text-transform:uppercase;color:#fff;background:var(--celadon);padding:3px 8px;border-radius:999px;z-index:2}\n.visitedline{display:flex;align-items:center;gap:10px;margin-top:8px;flex-wrap:wrap}\n.visited-count{font-family:var(--sans);font-size:.82rem;color:var(--ink-soft);font-weight:600}\n.hidev-btn{display:inline-flex;align-items:center;gap:7px;background:transparent;color:var(--ink);border:1.5px solid var(--line);font-family:inherit;font-weight:700;font-size:.82rem;cursor:pointer;padding:7px 15px;border-radius:999px}\n.hidev-btn.active{background:var(--celadon);color:#fff;border-color:var(--celadon)}\n.naver{display:inline-flex;align-items:center;gap:6px;font-family:var(--sans);font-weight:700;font-size:.82rem;text-decoration:none;color:#fff;background:#03c75a;padding:8px 13px;border-radius:10px;cursor:pointer;border:0}\n.naver:hover{filter:brightness(.94)}\n.naver .nlogo{display:inline-flex;align-items:center;justify-content:center;width:16px;height:16px;background:#fff;color:#03c75a;border-radius:4px;font-weight:900;font-size:.72rem;line-height:1}\n.share{display:inline-flex;align-items:center;gap:6px;font-family:var(--sans);font-weight:700;font-size:.82rem;color:var(--ink);background:transparent;border:1.5px solid var(--line);padding:7px 13px;border-radius:10px;cursor:pointer}\n.share:hover{border-color:var(--ink-soft)}\n.share svg{width:15px;height:15px}\n@keyframes cardflash{0%{box-shadow:0 0 0 0 rgba(200,71,47,0)}20%{box-shadow:0 0 0 3px var(--persimmon)}100%{box-shadow:0 0 0 0 rgba(200,71,47,0)}}\n.card.flash{animation:cardflash 1.9s ease}\n'

GUIDE_JS = "\n(function(){\n  var region=document.getElementById('resultsRegion')||document.body;\n  var state=region._state||(region._state={plat:'all',topic:'all',hideVisited:false});\n  var LSP='vip-visited:';\n  function lsGet(k){try{return localStorage.getItem(LSP+k)==='1';}catch(e){return false;}}\n  function lsSet(k,v){try{if(v)localStorage.setItem(LSP+k,'1');else localStorage.removeItem(LSP+k);}catch(e){}}\n  function sval(){var s=region.querySelector('#gSearch');return s?s.value.trim().toLowerCase():'';}\n  function openNaver(nmapUrl, webUrl){\n    // Try the Naver Map app via the URL scheme; if it doesn't take over the\n    // page within ~1.2s (app not installed / desktop), open the Naver web map.\n    var hidden=false;\n    function onHide(){hidden=true;}\n    document.addEventListener('visibilitychange', onHide);\n    window.addEventListener('pagehide', onHide);\n    var ifr=document.createElement('iframe');\n    ifr.style.display='none'; document.body.appendChild(ifr);\n    try{ ifr.src=nmapUrl; }catch(e){}\n    setTimeout(function(){\n      document.removeEventListener('visibilitychange', onHide);\n      window.removeEventListener('pagehide', onHide);\n      try{ document.body.removeChild(ifr); }catch(e){}\n      if(!hidden && webUrl){ window.open(webUrl, '_blank', 'noopener'); }\n    }, 1200);\n  }\n  function shareFlash(btn,msg){var l=btn.querySelector('.slabel');if(!l)return;var o=l.getAttribute('data-o')||l.textContent;l.setAttribute('data-o',o);l.textContent=msg;setTimeout(function(){l.textContent=o;},1500);}\n  function doShare(btn){\n    var title=btn.getAttribute('data-title')||'';\n    var text=btn.getAttribute('data-text')||'';\n    var hash=btn.getAttribute('data-hash')||'';\n    var pageUrl='';\n    if(location.protocol==='http:'||location.protocol==='https:'){pageUrl=location.origin+location.pathname+hash;}\n    var full=text+(pageUrl?('\\n'+pageUrl):'');\n    if(navigator.share){\n      var d={title:title,text:text}; if(pageUrl)d.url=pageUrl;\n      navigator.share(d).catch(function(){});\n      return;\n    }\n    if(navigator.clipboard&&navigator.clipboard.writeText){\n      navigator.clipboard.writeText(full).then(function(){shareFlash(btn,'Copied!');},function(){shareFlash(btn,'Copy failed');});\n      return;\n    }\n    try{var ta=document.createElement('textarea');ta.value=full;ta.style.position='fixed';ta.style.opacity='0';document.body.appendChild(ta);ta.focus();ta.select();document.execCommand('copy');document.body.removeChild(ta);shareFlash(btn,'Copied!');}catch(e){shareFlash(btn,'Copy failed');}\n  }\n  function restore(){\n    [].slice.call(region.querySelectorAll('.visited-cb')).forEach(function(cb){\n      var v=lsGet(cb.getAttribute('data-key'));\n      cb.checked=v; var card=cb.closest('.card'); if(card)card.classList.toggle('visited',v);\n    });\n  }\n  function counts(){\n    var tot=region.querySelectorAll('.visited-cb').length;\n    var vis=region.querySelectorAll('.card.visited').length;\n    var el=region.querySelector('#gVisited'); if(el)el.textContent=vis+' / '+tot+' visited';\n  }\n  function apply(){\n    var query=sval(), shown=0;\n    [].slice.call(region.querySelectorAll('.section')).forEach(function(sec){\n      var secTopic=sec.getAttribute('data-topic'), vis=0;\n      [].slice.call(sec.querySelectorAll('.card')).forEach(function(c){\n        var okP=state.plat==='all'||c.getAttribute('data-plat')===state.plat;\n        var okT=state.topic==='all'||secTopic===state.topic;\n        var okQ=!query||c.textContent.toLowerCase().indexOf(query)>-1;\n        var okV=!(state.hideVisited&&c.classList.contains('visited'));\n        var show=okP&&okT&&okQ&&okV; c.hidden=!show; if(show){vis++;shown++;}\n      });\n      sec.hidden=vis===0;\n      var cnt=sec.querySelector('.cnt'); if(cnt)cnt.textContent=vis;\n    });\n    var rl=region.querySelector('#gResult'); if(rl)rl.textContent=shown+(shown===1?' video':' videos')+(query?(' \\u00b7 \\u201c'+query+'\\u201d'):'');\n    var emp=region.querySelector('#gEmpty'); if(emp)emp.style.display=shown===0?'block':'none';\n    counts();\n  }\n  restore();\n  if(!region.dataset.bound){\n    region.dataset.bound='1';\n    region.addEventListener('input',function(e){\n      if(e.target.id==='gSearch'){var cb=region.querySelector('#gClear'); if(cb)cb.style.display=e.target.value?'block':'none'; apply();}\n    });\n    region.addEventListener('change',function(e){\n      var t=e.target;\n      if(t.classList&&t.classList.contains('visited-cb')){\n        var card=t.closest('.card'); if(card)card.classList.toggle('visited',t.checked);\n        lsSet(t.getAttribute('data-key'),t.checked); apply();\n      }\n    });\n    region.addEventListener('click',function(e){\n      var nav=e.target.closest('.naver');\n      if(nav){e.preventDefault();openNaver(nav.getAttribute('data-nmap'),nav.getAttribute('data-web'));return;}\n      var sh=e.target.closest('.share');\n      if(sh){e.preventDefault();doShare(sh);return;}\n      var hv=e.target.closest('#gHideVisited');\n      if(hv){state.hideVisited=!state.hideVisited;hv.classList.toggle('active',state.hideVisited);hv.textContent=state.hideVisited?'Show visited':'Hide visited';apply();return;}\n      var seg=e.target.closest('#gSeg button');\n      if(seg){[].forEach.call(region.querySelectorAll('#gSeg button'),function(x){x.classList.remove('active');});seg.classList.add('active');state.plat=seg.getAttribute('data-plat');apply();return;}\n      var chip=e.target.closest('.chip');\n      if(chip){[].forEach.call(region.querySelectorAll('.chip'),function(x){x.classList.remove('active');});chip.classList.add('active');state.topic=chip.getAttribute('data-topic');apply();window.scrollTo({top:0,behavior:'smooth'});return;}\n      var cb=e.target.closest('#gClear');\n      if(cb){var s=region.querySelector('#gSearch');if(s)s.value='';cb.style.display='none';apply();return;}\n      var more=e.target.closest('.more');\n      if(more){var card=more.closest('.card');var ex=card.querySelector('.extra');var d=card.querySelector('.desc');if(ex){ex.classList.toggle('open');var op=ex.classList.contains('open');more.textContent=op?'Show less \\u2191':'Show more \\u2193';if(d)d.classList.toggle('clamp',!op);}return;}\n      var tag=e.target.closest('.tag');\n      if(tag){var s2=region.querySelector('#gSearch');if(s2){s2.value=tag.getAttribute('data-tag');var cb2=region.querySelector('#gClear');if(cb2)cb2.style.display='block';}apply();window.scrollTo({top:0,behavior:'smooth'});return;}\n    });\n  }\n  if(!window._gtopBound){\n    window._gtopBound=1;\n    var gt=document.getElementById('gTop');\n    if(gt){window.addEventListener('scroll',function(){gt.classList.toggle('show',window.scrollY>600);});gt.addEventListener('click',function(){window.scrollTo({top:0,behavior:'smooth'});});}\n  }\n  apply();\n  if(location.hash&&location.hash.length>1){\n    var tgt=document.getElementById(location.hash.slice(1));\n    if(tgt){setTimeout(function(){tgt.scrollIntoView({behavior:'smooth',block:'center'});tgt.classList.add('flash');setTimeout(function(){tgt.classList.remove('flash');},2000);},250);}\n  }\n})();\n"

